23	template <typename Func> void visit_netlist_variables(NetlistContext &netlist, Func &&visit_fn)
24	{
25		netlist.realm.visit(ast::makeVisitor(
26				[&](auto &, const ast::VariableSymbol &symbol) {
27					if (symbol.getType().isFixedSize() &&
28							symbol.lifetime == ast::VariableLifetime::Static) {
29						visit_fn(symbol);
30					}
31				},
32				[&](auto &visitor, const ast::InstanceSymbol &symbol) {
33					if (netlist.should_dissolve(symbol))
34						visitor.visitDefault(symbol);
35				},
36				[&](auto &, const ast::ProceduralBlockSymbol &) {
37					// TODO: check
38					/* do not descend into procedural blocks */
39				},
40				[&](auto &visitor, const ast::GenerateBlockSymbol &symbol) {
41					/* stop at uninstantiated generate blocks */
42					if (symbol.isUninstantiated)
43						return;
44					visitor.visitDefault(symbol);
45				}));
46	
47		for (auto conn : netlist.realm.parentInstance->getPortConnections()) {
48			if (conn->port.kind == ast::SymbolKind::InterfacePort &&
49					/* modport */ conn->getIfaceConn().second != nullptr) {
50				const ast::Symbol &iface_instance = *conn->getIfaceConn().first;
51				const ast::ModportSymbol &ref_modport = *conn->getIfaceConn().second;
52				iface_instance.visit(ast::makeVisitor(
53						[&](auto &visitor, const ast::InstanceArraySymbol &symbol) {
54							// Mock instance array symbols made up by slang don't contain
55							// the instances as members, but they do contain them as elements
56							for (auto &elem : symbol.elements)
57								elem->visit(visitor);
58						},
59						[&](auto &visitor, const ast::ModportSymbol &modport) {
60							// To support interface arrays, we need to match all modports
61							// with the same name as ref_modport
62							if (!modport.name.compare(ref_modport.name)) {
63								visitor.visitDefault(modport);
64							}
65						},
66						[&](auto &, const ast::ModportPortSymbol &port) {
67							// TODO: graceful handling
68							ast_invariant(port, port.internalSymbol);
69							if (ast::VariableSymbol::isKind(port.internalSymbol->kind) &&
70									port.getType().isFixedSize()) {
71								ast_invariant(
72										port, port.internalSymbol->as<ast::VariableSymbol>().lifetime ==
73													  ast::VariableLifetime::Static);
74								visit_fn(port);
75							}
76						}));
77			}
78		}
79	}
