81	void evaluate_decl_initializers(NetlistContext &netlist)
82	{
83		visit_netlist_variables(netlist, [&](const ast::ValueSymbol &symbol) {
84			const ast::VariableSymbol *variable = nullptr;
85			if (ast::VariableSymbol::isKind(symbol.kind)) {
86				variable = &symbol.as<ast::VariableSymbol>();
87			} else if (ast::ModportPortSymbol::isKind(symbol.kind)) {
88				auto &port = symbol.as<ast::ModportPortSymbol>();
89				ast_invariant(port, port.internalSymbol != nullptr);
90				ast_invariant(port, ast::VariableSymbol::isKind(port.internalSymbol->kind));
91				variable = &port.internalSymbol->as<ast::VariableSymbol>();
92			} else {
93				ast_unreachable(symbol);
94			}
95	
96			// Use ProceduralContext to get $meminit emission if the target is a memory
97			ProceduralContext context(netlist, ProcessTiming::initial);
98			RTLIL::SigSpec value;
99	
100			const ast::Expression *initializer = nullptr;
101	
102			if (symbol.getInitializer()) {
103				initializer = symbol.getInitializer();
104			} else {
105				for (const ast::ValueSymbol::PortBackref *backref = symbol.getFirstPortBackref();
106						backref; backref = backref->getNextBackreference()) {
107					if (backref->port->internalSymbol == &symbol &&
108							backref->port->direction == ast::ArgumentDirection::Out &&
109							backref->port->getInitializer()) {
110						initializer = backref->port->getInitializer();
111						break;
112					}
113				}
114			}
115	
116			if (initializer) {
117				context.do_simple_assign(symbol.location, context.eval.variable(symbol),
118						context.eval(*initializer), true);
119			} else if (!symbol.getType().isFourState()) {
120				if (auto converted = netlist.convert_const(
121							symbol.getType().getDefaultValue(), variable->location)) {
122					context.do_simple_assign(
123							symbol.location, context.eval.variable(symbol), *converted, true);
124				}
125			}
126		});
127	}
128	
129	void finalize_variable_initialization(NetlistContext &netlist)
130	{
131		visit_netlist_variables(netlist, [&](const ast::ValueSymbol &symbol) {
132			const ast::VariableSymbol *variable_symbol = nullptr;
133			if (ast::VariableSymbol::isKind(symbol.kind)) {
134				variable_symbol = &symbol.as<ast::VariableSymbol>();
135			} else if (ast::ModportPortSymbol::isKind(symbol.kind)) {
136				auto &port = symbol.as<ast::ModportPortSymbol>();
137				ast_invariant(port, port.internalSymbol != nullptr);
138				ast_invariant(port, ast::VariableSymbol::isKind(port.internalSymbol->kind));
139				variable_symbol = &port.internalSymbol->as<ast::VariableSymbol>();
140			} else {
141				ast_unreachable(symbol);
142			}
143	
144			auto variable = Variable::from_symbol(&symbol);
145			if (netlist.is_inferred_memory(*variable_symbol)) {
146				// Nothing to do
147			} else {
148				auto signal = netlist.convert_static(variable);
149				RTLIL::SigSpec cl, cr; // lhs/rhs of a new connection
150				RTLIL::Const attr_value(RTLIL::Sx, signal.size());
151				for (int i = 0; i < signal.size(); i++) {
152					VariableBit vbit(variable, i);
153					bool register_driven = netlist.register_driven_variables.count(vbit);
154					bool driven = netlist.driven_variables.count(vbit);
155					// register_driven implies driven
156					log_assert(!register_driven || driven);
157					RTLIL::State state = netlist.initial_state.at(vbit, RTLIL::Sx);
158					if (register_driven) {
159	#if YOSYS_MAJOR == 0 && YOSYS_MINOR < 58
160						attr_value.bits()[i] = state;
161	#else
162						attr_value.set(i, state);
163	#endif
164					} else {
165						if (!driven) {
166							cl.append(signal[i]);
167							cr.append(state);
168						}
169					}
170				}
171	
172				if (!attr_value.is_fully_undef()) {
173					log_assert(signal.is_wire());
174					RTLIL::Wire *wire = signal.chunks().begin()->wire;
175					wire->attributes[ID::init] = attr_value;
176				}
177				netlist.connect(cl, cr);
178			}
179		});
180	}
181	
182	}; // namespace slang_frontend
