35	
36			for (auto &field : scope->template membersOfType<ast::FieldSymbol>()) {
37				uint64_t field_offset = bitstream_member_offset(field);
38				subfield_names(chunk, type_offset + field_offset, &field.getType(),
39						prefix + "." + std::string(field.name), ret);
40			}
41		} else if (type->isArray() && !type->isSimpleBitVector()) {
42			log_assert(type->hasFixedRange());
43			auto range = type->getFixedRange();
44			const ast::Type *el_type = type->getArrayElementType();
45			uint64_t stride = el_type->getBitstreamWidth();
46	
47			for (int i = range.lower(); i <= range.upper(); i++) {
48				uint64_t elem_offset = range.translateIndex(i) * stride;
49				subfield_names(chunk, type_offset + elem_offset, el_type,
50						prefix + "[" + std::to_string(i) + "]", ret);
51			}
52		} else {
53			uint64_t width = type->getBitstreamWidth();
54			uint64_t lo = chunk.base > type_offset ? std::min(chunk.base - type_offset, width) : 0;
55			uint64_t hi = chunk.base + chunk.bitwidth() > type_offset
56								  ? std::min(chunk.base + chunk.bitwidth() - type_offset, width)
57								  : 0;
58	
59			log_assert(hi > lo);
60			if (lo == 0 && hi == width)
61				ret.emplace_back(VariableChunk{chunk.variable, type_offset, width}, prefix);
