bool is_special_net_type(const ast::NetType &type)
{
	switch (type.netKind) {
		case ast::NetType::WAnd:
		case ast::NetType::WOr:
		case ast::NetType::TriAnd:
		case ast::NetType::TriOr:
			return true;
		case ast::NetType::Wire:
